const body = $input.first().json.body;
const pr = body.pull_request;
const review = body.review;
const repo = body.repository;

return [{
  json: {
    prNumber: pr.number,
    prTitle: pr.title,
    prUrl: pr.html_url,
    headBranch: pr.head.ref,
    headSha: pr.head.sha,
    repoOwner: repo.owner.login,
    repoName: repo.name,
    reviewBody: review.body || '',
    reviewState: review.state,
    reviewId: review.id
  }
}];

const prInfo = $('PR 정보 추출').first().json;
const inlineComments = $('GitHub: 리뷰 인라인 코멘트 조회').all().map(i => i.json);
const prFiles = $input.all().map(f => f.json);

// Gemini 인라인 코멘트 필터링
const geminiComments = inlineComments.filter(c =>
  c.user && c.user.login === 'gemini-code-assist[bot]'
);

// 코멘트 텍스트 정리
const commentsText = geminiComments.length > 0
  ? geminiComments.map(c => `📍 ${c.path} (line ${c.original_line || c.line || '?'}):\n${c.body}`).join('\n\n')
  : '(인라인 코멘트 없음)';

// 변경 파일 목록
const filePaths = prFiles.map(f => f.filename);

// 리뷰 전체 요약
const reviewSummary = [
  `## Gemini 리뷰 요약\n${prInfo.reviewBody || '(없음)'}`,
  `## 인라인 코멘트\n${commentsText}`
].join('\n\n');

return [{
  json: {
    ...prInfo,
    reviewSummary,
    filePaths,
    hasComments: geminiComments.length > 0 || prInfo.reviewBody.length > 0
  }
}];

// 변경된 파일들을 읽기 위해 각 파일 경로를 개별 아이템으로 분리
const ctx = $input.first().json;
return ctx.filePaths.map(path => ({
  json: {
    path,
    branch: ctx.headBranch,
    repoOwner: ctx.repoOwner,
    repoName: ctx.repoName,
    // 전체 컨텍스트도 함께 전달
    _ctx: ctx
  }
}));

const fileItems = $('GitHub: 파일 내용 읽기').all();
const splitItems = $('파일 목록 분리').all();
const ctx = splitItems[0].json._ctx;

const files = fileItems.map((item, i) => {
  const content = Buffer.from((item.json.content || '').replace(/\n/g, ''), 'base64').toString('utf8');
  return {
    path: item.json.path,
    content,
    sha: item.json.sha
  };
});

const filesContext = files.map(f =>
  `### ${f.path}\n\`\`\`typescript\n${f.content}\n\`\`\``
).join('\n\n');

// CI 실패 정보 조회
const token = $env.GITHUB_TOKEN;
function ghGet(path) {
  return new Promise((resolve, reject) => {
    const https = require('https');
    const url = new URL(`https://api.github.com${path}`);
    const req = https.request({
      hostname: url.hostname,
      path: url.pathname + url.search,
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Accept': 'application/vnd.github+json',
        'X-GitHub-Api-Version': '2022-11-28',
        'User-Agent': 'n8n-jump-section'
      }
    }, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) reject(new Error(`HTTP ${res.statusCode}: ${data}`));
        else resolve(JSON.parse(data));
      });
    });
    req.on('error', reject);
    req.end();
  });
}

let ciSection = '';
try {
  const checkData = await ghGet(`/repos/${ctx.repoOwner}/${ctx.repoName}/commits/${ctx.headSha}/check-runs?per_page=30`);
  const failed = (checkData.check_runs || []).filter(c =>
    c.conclusion === 'failure' || c.conclusion === 'timed_out'
  );
  if (failed.length > 0) {
    const details = failed.map(c => {
      const lines = [`### ❌ ${c.name}`];
      if (c.output?.summary) lines.push(c.output.summary);
      if (c.output?.text) lines.push(c.output.text.slice(0, 3000));
      return lines.join('\n');
    }).join('\n\n');
    ciSection = `## CI 실패 정보\n\n${details}\n\n`;
  }
} catch (e) {
  ciSection = `## CI 실패 정보\n\n(조회 실패: ${e.message})\n\n`;
}

const userPrompt = `## PR #${ctx.prNumber}: ${ctx.prTitle}\n브랜치: \`${ctx.headBranch}\`\n\n## Gemini 리뷰\n${ctx.reviewSummary}\n\n${ciSection}---\n\n## 현재 코드\n\n${filesContext}\n\n---\n\nGemini 리뷰를 반영하고, CI 실패가 있다면 원인을 파악하여 함께 수정하세요. 타당한 지적만 반영하고, 수정한 파일을 write_file 함수로 제출하세요.`;

const geminiPayload = {
  system_instruction: {
    parts: [{ text: 'TypeScript 전문 개발자입니다. Gemini의 코드 리뷰 코멘트와 CI 실패 정보를 바탕으로 코드를 수정합니다.\n\n규칙:\n- Gemini 코멘트에서 타당한 지적만 수정 (스타일 의견은 기존 코드 스타일 우선)\n- CI 실패가 있으면 반드시 원인을 파악하고 수정 (format check, type error, test failure, build error 등)\n- 기존 Public API 하위 호환성 유지\n- Prettier 포맷 준수 (2sp, 세미콜론, 싱글쿼트, printWidth 100)\n- 수정이 필요 없는 파일은 write_file 호출 생략\n- 반드시 write_file 함수로 수정된 파일 제출' }]
  },
  contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
  tools: [{
    functionDeclarations: [{
      name: 'write_file',
      description: '수정된 파일의 전체 내용을 제출합니다.',
      parameters: {
        type: 'OBJECT',
        properties: {
          path: { type: 'STRING', description: '파일 경로' },
          content: { type: 'STRING', description: '파일 전체 내용' },
          description: { type: 'STRING', description: '변경 설명' }
        },
        required: ['path', 'content', 'description']
      }
    }]
  }],
  toolConfig: { functionCallingConfig: { mode: 'AUTO' } },
  generationConfig: { maxOutputTokens: 8192 }
};

return [{
  json: {
    ...ctx,
    files,
    hasCiFailures: ciSection !== '',
    geminiPayload
  }
}];

const response = $input.first().json;
const ctx = $('파일 내용 디코딩').first().json;

const parts = response.candidates[0].content.parts;
const functionCalls = parts.filter(p => p.functionCall && p.functionCall.name === 'write_file');

if (functionCalls.length === 0) {
  // 수정 필요 없음
  return [{ json: { noChanges: true, ...ctx } }];
}

const fixedFiles = functionCalls.map(p => {
  const original = ctx.files.find(f => f.path === p.functionCall.args.path);
  return {
    path: p.functionCall.args.path,
    content: p.functionCall.args.content,
    description: p.functionCall.args.description,
    sha: original?.sha || null
  };
});

const filesSummary = fixedFiles.map(f => `• \`${f.path}\`: ${f.description}`).join('\n');

return [{
  json: {
    noChanges: false,
    fixedFiles,
    filesSummary,
    prNumber: ctx.prNumber,
    prTitle: ctx.prTitle,
    prUrl: ctx.prUrl,
    headBranch: ctx.headBranch,
    repoOwner: ctx.repoOwner,
    repoName: ctx.repoName
  }
}];

const data = $input.first().json;
const { fixedFiles, headBranch, repoOwner, repoName, filesSummary } = data;
const token = $env.GITHUB_TOKEN;

const headers = {
  'Authorization': `Bearer ${token}`,
  'Accept': 'application/vnd.github+json',
  'X-GitHub-Api-Version': '2022-11-28',
  'Content-Type': 'application/json'
};

const baseUrl = `https://api.github.com/repos/${repoOwner}/${repoName}`;

function request(method, url, body) {
  return new Promise((resolve, reject) => {
    const https = require('https');
    const urlObj = new URL(url);
    const options = { hostname: urlObj.hostname, path: urlObj.pathname + urlObj.search, method, headers };
    const req = https.request(options, (res) => {
      let d = '';
      res.on('data', chunk => d += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) reject(new Error(`HTTP ${res.statusCode}: ${d}`));
        else resolve(JSON.parse(d));
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

// 1. HEAD SHA
const refData = await request('GET', `${baseUrl}/git/refs/heads/${headBranch}`);
const baseSha = refData.object.sha;

// 2. 현재 트리 SHA
const commitData = await request('GET', `${baseUrl}/git/commits/${baseSha}`);
const baseTreeSha = commitData.tree.sha;

// 3. 새 트리 생성 (모든 파일 한번에)
const newTree = await request('POST', `${baseUrl}/git/trees`, {
  base_tree: baseTreeSha,
  tree: fixedFiles.map(f => ({ path: f.path, mode: '100644', type: 'blob', content: f.content }))
});

// 4. 커밋 생성
const newCommit = await request('POST', `${baseUrl}/git/commits`, {
  message: `fix: apply Gemini review suggestions\n\n${filesSummary}`,
  tree: newTree.sha,
  parents: [baseSha]
});

// 5. 브랜치 ref 업데이트
await request('PATCH', `${baseUrl}/git/refs/heads/${headBranch}`, { sha: newCommit.sha });

return [{ json: { ...data, commitSha: newCommit.sha } }];

